     1→"use client";
     2→
     3→import { createContext, useContext, useState, ReactNode, useMemo } from "react";
     4→
     5→type PaymentStatus = "idle" | "processing" | "succeeded" | "failed";
     6→
     7→interface MembershipContextValue {
     8→  walletAddress: string | null;
     9→  setWalletAddress: (address: string | null) => void;
    10→  paymentStatus: PaymentStatus;
    11→  setPaymentStatus: (status: PaymentStatus) => void;
    12→  isAuthenticated: boolean;
    13→  isUnlocked: boolean;
    14→}
    15→
    16→const MembershipContext = createContext<MembershipContextValue | null>(null);
    17→
    18→interface MembershipProviderProps {
    19→  children: ReactNode;
    20→  initialUnlocked?: boolean;
    21→}
    22→
    23→export function MembershipProvider({
    24→  children,
    25→  initialUnlocked = false,
    26→}: MembershipProviderProps) {
    27→  const [walletAddress, setWalletAddress] = useState<string | null>(null);
    28→  const [paymentStatus, setPaymentStatus] = useState<PaymentStatus>(
    29→    initialUnlocked ? "succeeded" : "idle"
    30→  );
    31→
    32→  const value = useMemo<MembershipContextValue>(
    33→    () => ({
    34→      walletAddress,
    35→      setWalletAddress,
    36→      paymentStatus,
    37→      setPaymentStatus,
    38→      isAuthenticated: !!walletAddress,
    39→      isUnlocked: paymentStatus === "succeeded",
    40→    }),
    41→    [walletAddress, paymentStatus]
    42→  );
    43→
    44→  return (
    45→    <MembershipContext.Provider value={value}>
    46→      {children}
    47→    </MembershipContext.Provider>
    48→  );
    49→}
    50→
    51→export function useMembership(): MembershipContextValue {
    52→  const ctx = useContext(MembershipContext);
    53→  if (!ctx) {
    54→    throw new Error("useMembership must be used within a MembershipProvider");
    55→  }
    56→  return ctx;
    57→}
