     3→import { useState, useEffect, useRef, ReactNode } from "react";
     4→import { Elements } from "@stripe/react-stripe-js";
     5→import { getStripe } from "@/app/lib/stripe";
     6→import { useMembership } from "@/app/components/providers/MembershipContext";
     7→import type { Stripe, StripeElementsOptions } from "@stripe/stripe-js";
     8→
     9→interface StripeProviderProps {
    10→  children: ReactNode;
    11→}
    12→
    13→export default function StripeProvider({ children }: StripeProviderProps) {
    14→  const { walletAddress } = useMembership();
    15→  const [stripe, setStripe] = useState<Stripe | null>(null);
    16→  const [clientSecret, setClientSecret] = useState<string | null>(null);
    17→  const [error, setError] = useState<string | null>(null);
    18→  const fetchedForAddress = useRef<string | null>(null);
    19→
    20→  useEffect(() => {
    21→    if (!walletAddress) return;
    22→    if (fetchedForAddress.current === walletAddress) return;
    23→    fetchedForAddress.current = walletAddress;
    24→
    25→    const stripePromise = getStripe();
    26→    if (!stripePromise) return;
    27→
    28→    stripePromise.then(setStripe);
    29→
    30→    fetch("/api/stripe/create-payment-intent", {
    31→      method: "POST",
    32→      headers: { "Content-Type": "application/json" },
    33→      body: JSON.stringify({ walletAddress }),
    34→    })
    35→      .then((res) => res.json())
    36→      .then((data) => {
    37→        if (data.clientSecret) {
    38→          setClientSecret(data.clientSecret);
    39→        } else {
    40→          setError(data.error || "Failed to create payment intent");
    41→        }
    42→      })
    43→      .catch(() => setError("Failed to connect to payment server"));
    44→  }, [walletAddress]);
    45→
    46→  if (error || !stripe || !clientSecret) {
    47→    return <>{children}</>;
    48→  }
    49→
    50→  const options: StripeElementsOptions = {
    51→    clientSecret,
    52→    appearance: {
    53→      theme: "stripe",
    54→      variables: {
    55→        colorPrimary: "#4f46e5",
    56→        borderRadius: "8px",
    57→      },
    58→    },
    59→  };
    60→
    61→  return (
    62→    <Elements stripe={stripe} options={options}>
    63→      {children}
    64→    </Elements>
    65→  );
    66→}
    67→

