     3→import { useEffect, useState } from "react";
     4→import { hasStripeKey } from "@/app/lib/stripe";
     5→
     6→interface SubscriptionStatus {
     7→  status: string;
     8→  cancelAtPeriodEnd?: boolean;
     9→  currentPeriodEnd?: string;
    10→}
    11→
    12→interface SubscriptionManagerProps {
    13→  walletAddress: string;
    14→}
    15→
    16→export default function SubscriptionManager({ walletAddress }: SubscriptionManagerProps) {
    17→  const [subStatus, setSubStatus] = useState<SubscriptionStatus | null>(null);
    18→  const [loading, setLoading] = useState(true);
    19→  const [canceling, setCanceling] = useState(false);
    20→  const [showConfirm, setShowConfirm] = useState(false);
    21→
    22→  useEffect(() => {
    23→    if (!hasStripeKey()) {
    24→      setLoading(false);
    25→      return;
    26→    }
    27→
    28→    fetch(`/api/stripe/subscription-status?walletAddress=${encodeURIComponent(walletAddress)}`)
    29→      .then((res) => res.json())
    30→      .then((data) => setSubStatus(data))
    31→      .catch(() => setSubStatus(null))
    32→      .finally(() => setLoading(false));
    33→  }, [walletAddress]);
    34→
    35→  if (!hasStripeKey() || loading) return null;
    36→  if (!subStatus || subStatus.status === "none") return null;
    37→
    38→  const endDate = subStatus.currentPeriodEnd
    39→    ? new Date(subStatus.currentPeriodEnd).toLocaleDateString()
    40→    : null;
    41→
    42→  async function handleCancel() {
    43→    setCanceling(true);
    44→    try {
    45→      const res = await fetch("/api/stripe/cancel-subscription", {
    46→        method: "POST",
    47→        headers: { "Content-Type": "application/json" },
    48→        body: JSON.stringify({ walletAddress }),
    49→      });
    50→      const data = await res.json();
    51→      if (res.ok) {
    52→        setSubStatus({
    53→          status: "active",
    54→          cancelAtPeriodEnd: true,
    55→          currentPeriodEnd: data.currentPeriodEnd,
    56→        });
    57→      }
    58→    } finally {
    59→      setCanceling(false);
    60→      setShowConfirm(false);
    61→    }
    62→  }
    63→
    64→  return (
    65→    <div className="mt-8 border-t border-gray-200 pt-6">
    66→      <h3 className="text-sm font-semibold text-gray-700 mb-2">Subscription</h3>
    67→
    68→      {subStatus.cancelAtPeriodEnd ? (
    69→        <p className="text-sm text-gray-600">
    70→          Your subscription ends on {endDate}. You will retain access until then.
    71→        </p>
    72→      ) : (
    73→        <>
    74→          <p className="text-sm text-gray-600 mb-3">
    75→            Your subscription is active. Next billing date: {endDate}
    76→          </p>
    77→
    78→          {showConfirm ? (
    79→            <div className="flex items-center gap-3">
    80→              <span className="text-sm text-gray-700">
    81→                Are you sure you want to cancel?
    82→              </span>
    83→              <button
    84→                onClick={handleCancel}
    85→                disabled={canceling}
    86→                className="text-sm font-medium text-red-600 hover:text-red-700 disabled:opacity-50"
    87→              >
    88→                {canceling ? "Canceling..." : "Yes, cancel"}
    89→              </button>
    90→              <button
    91→                onClick={() => setShowConfirm(false)}
    92→                className="text-sm font-medium text-gray-500 hover:text-gray-700"
    93→              >
    94→                No, keep it
    95→              </button>
    96→            </div>
    97→          ) : (
