     9→export function hasThirdWebEngineConfig(): boolean {
    10→  return REQUIRED_ENV_VARS.every((key) => !!process.env[key]);
    11→}
    12→
    13→export async function mintMembershipNFT(
    14→  walletAddress: string
    15→): Promise<{ success: boolean; queueId?: string; error?: string }> {
    16→  const engineUrl = process.env.THIRDWEB_ENGINE_URL;
    17→  const accessToken = process.env.THIRDWEB_ENGINE_ACCESS_TOKEN;
    18→  const backendWallet = process.env.THIRDWEB_ENGINE_BACKEND_WALLET;
    19→  const contractAddress = process.env.NFT_CONTRACT_ADDRESS;
    20→  const chainId = process.env.NFT_CHAIN_ID;
    21→
    22→  if (!engineUrl || !accessToken || !backendWallet || !contractAddress || !chainId) {
    23→    return { success: false, error: "ThirdWeb Engine environment variables not configured" };
    24→  }
    25→
    26→  const url = `${engineUrl}/contract/${chainId}/${contractAddress}/erc721/mint-to`;
    27→
    28→  const res = await fetch(url, {
    29→    method: "POST",
    30→    headers: {
    31→      "Content-Type": "application/json",
    32→      Authorization: `Bearer ${accessToken}`,
    33→      "x-backend-wallet-address": backendWallet,
    34→    },
    35→    body: JSON.stringify({
    36→      receiver: walletAddress,
    37→      metadata: {
    38→        name: "The Paywall Times Membership",
    39→        description: "Monthly membership NFT for The Paywall Times",
    40→      },
    41→    }),
    42→  });
    43→
    44→  if (!res.ok) {
    45→    const text = await res.text();
    46→    return { success: false, error: `Engine responded ${res.status}: ${text}` };
    47→  }
    48→
    49→  const data = await res.json();
    50→  return { success: true, queueId: data.result?.queueId };
    51→}
    52→
    53→export async function burnMembershipNFT(
    54→  walletAddress: string
    55→): Promise<{ success: boolean; queueId?: string; error?: string }> {
    56→  const engineUrl = process.env.THIRDWEB_ENGINE_URL;
    57→  const accessToken = process.env.THIRDWEB_ENGINE_ACCESS_TOKEN;
    58→  const backendWallet = process.env.THIRDWEB_ENGINE_BACKEND_WALLET;
    59→  const contractAddress = process.env.NFT_CONTRACT_ADDRESS;
    60→  const chainId = process.env.NFT_CHAIN_ID;
    61→
    62→  if (!engineUrl || !accessToken || !backendWallet || !contractAddress || !chainId) {
    63→    return { success: false, error: "ThirdWeb Engine environment variables not configured" };
    64→  }
    65→
    66→  // Find token IDs owned by this wallet
    67→  const ownedUrl = `${engineUrl}/contract/${chainId}/${contractAddress}/erc721/get-owned?ownerWallet=${walletAddress}`;
    68→  const ownedRes = await fetch(ownedUrl, {
    69→    headers: {
    70→      Authorization: `Bearer ${accessToken}`,
    71→    },
    72→  });
    73→
    74→  if (!ownedRes.ok) {
    75→    const text = await ownedRes.text();
    76→    return { success: false, error: `Failed to fetch owned tokens: ${ownedRes.status}: ${text}` };
    77→  }
    78→
    79→  const ownedData = await ownedRes.json();
    80→  const tokens: { metadata: { id: string } }[] = ownedData.result ?? [];
    81→
    82→  if (tokens.length === 0) {
    83→    return { success: true };
    84→  }
    85→
    86→  // Burn the latest token
    87→  const latestTokenId = tokens[tokens.length - 1].metadata.id;
    88→  const burnUrl = `${engineUrl}/contract/${chainId}/${contractAddress}/erc721/burn`;
    89→
    90→  const burnRes = await fetch(burnUrl, {
    91→    method: "POST",
    92→    headers: {
    93→      "Content-Type": "application/json",
    94→      Authorization: `Bearer ${accessToken}`,
    95→      "x-backend-wallet-address": backendWallet,
    96→    },
    97→    body: JSON.stringify({ tokenId: latestTokenId }),
    98→  });
    99→
   100→  if (!burnRes.ok) {
   101→    const text = await burnRes.text();
   102→    return { success: false, error: `Burn failed ${burnRes.status}: ${text}` };
   103→  }
   104→
   105→  const burnData = await burnRes.json();
   106→  return { success: true, queueId: burnData.result?.queueId };
   107→}
