     1→import { NextResponse } from "next/server";
     2→import Stripe from "stripe";
     3→import { mintMembershipNFT, burnMembershipNFT, hasThirdWebEngineConfig } from "@/app/lib/thirdweb-engine";
     4→
     5→export async function POST(request: Request) {
     6→  const secretKey = process.env.STRIPE_SECRET_KEY;
     7→  const webhookSecret = process.env.STRIPE_WEBHOOK_SECRET;
     8→
     9→  if (!secretKey || !webhookSecret) {
    10→    return NextResponse.json(
    11→      { error: "Stripe webhook not configured" },
    12→      { status: 500 }
    13→    );
    14→  }
    15→
    16→  const stripe = new Stripe(secretKey);
    17→
    18→  const rawBody = await request.text();
    19→  const sigHeader = request.headers.get("stripe-signature");
    20→
    21→  if (!sigHeader) {
    22→    return NextResponse.json({ error: "Missing stripe-signature header" }, { status: 400 });
    23→  }
    24→
    25→  let event: Stripe.Event;
    26→  try {
    27→    event = stripe.webhooks.constructEvent(rawBody, sigHeader, webhookSecret);
    28→  } catch (err) {
    29→    const message = err instanceof Error ? err.message : "Signature verification failed";
    30→    console.error(`Webhook signature verification failed: ${message}`);
    31→    return NextResponse.json({ error: message }, { status: 400 });
    32→  }
    33→
    34→  switch (event.type) {
    35→    case "invoice.payment_succeeded": {
    36→      const invoice = event.data.object as Stripe.Invoice;
    37→      const metadata = invoice.parent?.subscription_details?.metadata;
    38→
    39→      if (metadata?.mintNft === "true" && metadata.walletAddress) {
    40→        const subscriptionId =
    41→          typeof invoice.parent?.subscription_details?.subscription === "string"
    42→            ? invoice.parent.subscription_details.subscription
    43→            : invoice.parent?.subscription_details?.subscription?.id;
    44→
    45→        if (subscriptionId) {
    46→          // Idempotency: check if we already minted for this invoice
    47→          const sub = await stripe.subscriptions.retrieve(subscriptionId);
    48→          if (sub.metadata.lastMintedInvoice === invoice.id) {
    49→            console.log(`Mint already completed for invoice ${invoice.id}, skipping`);
    50→            break;
    51→          }
    52→
    53→          if (!hasThirdWebEngineConfig()) {
    54→            console.warn("ThirdWeb Engine not configured — skipping NFT mint");
    55→            break;
    56→          }
    57→
    58→          console.log(`Minting membership NFT to ${metadata.walletAddress} for invoice ${invoice.id}`);
    59→          const result = await mintMembershipNFT(metadata.walletAddress);
    60→
    61→          if (result.success) {
    62→            console.log(`Mint queued: ${result.queueId}`);
    63→            await stripe.subscriptions.update(subscriptionId, {
    64→              metadata: { ...sub.metadata, lastMintedInvoice: invoice.id },
    65→            });
    66→          } else {
    67→            console.error(`Mint failed: ${result.error}`);
    68→          }
    69→        }
    70→      }
    71→      break;
    72→    }
    73→
    74→    case "customer.subscription.deleted": {
    75→      const subscription = event.data.object as Stripe.Subscription;
    76→      const walletAddress = subscription.metadata?.walletAddress;
    77→      console.log(
    78→        `Subscription ${subscription.id} cancelled for customer ${subscription.customer}`
    79→      );
    80→
    81→      if (walletAddress && hasThirdWebEngineConfig()) {
    82→        console.log(`Burning membership NFT for wallet ${walletAddress}`);
    83→        const burnResult = await burnMembershipNFT(walletAddress);
    84→        if (burnResult.success) {
    85→          console.log(`Burn queued: ${burnResult.queueId ?? "no tokens to burn"}`);
    86→        } else {
    87→          console.error(`Burn failed: ${burnResult.error}`);
    88→        }
    89→      }
    90→      break;
    91→    }
    92→
    93→    default:
    94→      break;
    95→  }
    96→
    97→  return NextResponse.json({ received: true });
    98→}
    99→

